#include <stdio.h>
#include <stdlib.h>

int main() {
    int sx, sy;
    scanf("%d %d", &sx, &sy);

    int n;
    scanf("%d", &n);

    int found = 0;
    for (int i = 0; i < n; i++) {
        int lx, ly, r;
        scanf("%d %d %d", &lx, &ly, &r);
        int dist = abs(lx - sx) + abs(ly - sy);
        if (dist <= r) found = 1;
    }

    printf("%s\n", found ? "FOUND" : "LOST");
    return 0;
}
